// src/pages/Groups.jsx
import { useEffect, useRef, useState } from 'react';
import { GoogleMap, AdvancedMarkerElement } from '@react-google-maps/api';
import { fetchGroups } from '../services/api';
import GroupCard from '../components/GroupCards';
import CreateGroup from '../components/GroupCreate';
import '../styles/Groups.css';

const mapContainerStyle = {
    width: '100%',
    height: '400px',
    marginBottom: '2rem',
};

const defaultCenter = { lat: 46.603354, lng: 1.888334 }; // Centre France

export default function Groups() {
    const [groups, setGroups] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const mapRef = useRef(null);

    useEffect(() => {
        fetchGroups().then(setGroups);
    }, []);

    const handleCreate = (newGroup) => {
        setGroups((prev) => [...prev, newGroup]);
        setShowModal(false);
    };

    const flyTo = (group) => {
        if (group.location && mapRef.current) {
            mapRef.current.panTo(group.location);
            mapRef.current.setZoom(10);
        }
    };

    return (
        <div className="groups-container">
            <div className="groups-header">
                <h1 className="groups-title">Nos Groupes</h1>
                <button className="create-group-button" onClick={() => setShowModal(true)}>
                    Créer un Groupe
                </button>
            </div>

            <GoogleMap
                mapContainerStyle={mapContainerStyle}
                zoom={5}
                center={defaultCenter}
                onLoad={(map) => (mapRef.current = map)}
            >
                {groups.map((group) =>
                    group.location ? (
                        <AdvancedMarkerElement
                            key={group.id}
                            position={group.location}
                            title={group.name}
                        />
                    ) : null
                )}
            </GoogleMap>

            <div className="groups-grid">
                {groups.map((group) => (
                    <GroupCard
                        key={group.id}
                        {...group}
                        onClick={() => flyTo(group)}
                    />
                ))}
            </div>

            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <button className="close-modal" onClick={() => setShowModal(false)}>✖</button>
                        <CreateGroup onCreate={handleCreate} />
                    </div>
                </div>
            )}
        </div>
    );
}
